// Optional helper: AWS SigV4 presign generator (requires credentials provided securely).
class AwsSigV4Presigner {
  final String accessKeyId;
  final String secretAccessKey;
  final String region;
  final String service;

  AwsSigV4Presigner({
    required this.accessKeyId,
    required this.secretAccessKey,
    required this.region,
    this.service = 's3',
  });

  String presignUrl({
    required Uri endpoint,
    required String method,
    required String canonicalUri,
    required Map<String, String> queryParameters,
    required Map<String, String> headers,
    required Duration expires,
    required DateTime now,
    String payloadHash = 'UNSIGNED-PAYLOAD',
  }) {
    final amzDate = _formatAmzDate(now.toUtc());
    final dateStamp = _formatDate(now.toUtc());
    final credentialScope = '$dateStamp/$region/$service/aws4_request';

    final host = endpoint.host;
    final signedHeaders = (headers.keys.toList()..add('host'))
        .map((e) => e.toLowerCase())
        .toSet()
        .toList()
      ..sort();

    final canonicalHeadersMap = <String, String>{
      'host': host,
      ...headers.map((k, v) => MapEntry(k.toLowerCase(), v.trim())),
    };

    final qp = <String, String>{...queryParameters};
    qp['X-Amz-Algorithm'] = 'AWS4-HMAC-SHA256';
    qp['X-Amz-Credential'] = '${_uriEncode(accessKeyId)}/${_uriEncode(credentialScope)}';
    qp['X-Amz-Date'] = amzDate;
    qp['X-Amz-Expires'] = expires.inSeconds.toString();
    qp['X-Amz-SignedHeaders'] = signedHeaders.join(';');

    final canonicalQueryString = _canonicalQueryString(qp);
    final canonicalHeaders = signedHeaders.map((h) => '$h:${canonicalHeadersMap[h] ?? ''}\n').join();

    final canonicalRequest = [
      method.toUpperCase(),
      canonicalUri,
      canonicalQueryString,
      canonicalHeaders,
      signedHeaders.join(';'),
      payloadHash,
    ].join('\n');

    final stringToSign = [
      'AWS4-HMAC-SHA256',
      amzDate,
      credentialScope,
      sha256.convert(utf8.encode(canonicalRequest)).toString(),
    ].join('\n');

    final signingKey = _getSignatureKey(secretAccessKey, dateStamp, region, service);
    final signature = Hmac(sha256, signingKey).convert(utf8.encode(stringToSign)).toString();

    final signedUri = endpoint.replace(
      queryParameters: {
        ...qp,
        'X-Amz-Signature': signature,
      },
      path: canonicalUri,
    );

    return signedUri.toString();
  }

  static List<int> _getSignatureKey(String key, String dateStamp, String regionName, String serviceName) {
    final kDate = _hmac(utf8.encode('AWS4$key'), utf8.encode(dateStamp));
    final kRegion = _hmac(kDate, utf8.encode(regionName));
    final kService = _hmac(kRegion, utf8.encode(serviceName));
    final kSigning = _hmac(kService, utf8.encode('aws4_request'));
    return kSigning;
  }

  static List<int> _hmac(List<int> key, List<int> msg) => Hmac(sha256, key).convert(msg).bytes;

  static String _formatAmzDate(DateTime dt) {
    String two(int v) => v.toString().padLeft(2, '0');
    return '${dt.year}${two(dt.month)}${two(dt.day)}T${two(dt.hour)}${two(dt.minute)}${two(dt.second)}Z';
  }

  static String _formatDate(DateTime dt) {
    String two(int v) => v.toString().padLeft(2, '0');
    return '${dt.year}${two(dt.month)}${two(dt.day)}';
  }

  static String _canonicalQueryString(Map<String, String> params) {
    final keys = params.keys.toList()..sort();
    return keys
        .map((k) => '${_uriEncode(k)}=${_uriEncode(params[k] ?? '')}')
        .join('&');
  }

  static String _uriEncode(String s) {
    return Uri.encodeQueryComponent(s)
        .replaceAll('+', '%20')
        .replaceAll('%7E', '~');
  }
}

class S3UploaderViaPresignedPut {
  final http.Client client;

  S3UploaderViaPresignedPut({http.Client? client}) : client = client ?? http.Client();

  Future<void> putBytes({
    required String presignedUrl,
    required Uint8List bytes,
    required String contentType,
  }) async {
    final uri = Uri.parse(presignedUrl);
    final resp = await client.put(
      uri,
      headers: {
        'Content-Type': contentType,
      },
      body: bytes,
    );
    if (resp.statusCode < 200 || resp.statusCode >= 300) {
      throw Exception('S3 PUT failed: ${resp.statusCode} ${resp.body}');
    }
  }
}

class MultipartS3Uploader {
  // Not used by default; left for reference (requires AWS creds and policy/signing).
  final http.Client client;
  MultipartS3Uploader({http.Client? client}) : client = client ?? http.Client();

  Future<void> uploadViaFormPost({
    required Uri url,
    required Map<String, String> fields,
    required Uint8List fileBytes,
    required String fileFieldName,
    required String filename,
    required String contentType,
  }) async {
    final req = http.MultipartRequest('POST', url);
    req.fields.addAll(fields);
    req.files.add(
      http.MultipartFile.fromBytes(
        fileFieldName,
        fileBytes,
        filename: filename,
        contentType: MediaType.parse(contentType),
      ),
    );
    final streamed = await client.send(req);
    final respBody = await streamed.stream.bytesToString();
    if (streamed.statusCode < 200 || streamed.statusCode >= 300) {
      throw Exception('S3 form upload failed: ${streamed.statusCode} $respBody');
    }
  }
}

String randomKeySuffix([int length = 12]) {
  const chars = 'abcdefghijklmnopqrstuvwxyz0123456789';
  final r = Random.secure();
  return List.generate(length, (_) => chars[r.nextInt(chars.length)]).join();
}